<?php
if (!defined('ABSPATH')) exit;
function cdp_render_settings_page(){ if(!current_user_can('manage_options')) return; if(isset($_POST['cdp_save_settings'])){ check_admin_referer('cdp_save_settings'); update_option('cdp_support_email',sanitize_email($_POST['support_email']??'')); update_option('cdp_support_phone',sanitize_text_field($_POST['support_phone']??'')); update_option('cdp_support_url',esc_url_raw($_POST['support_url']??'')); update_option('cdp_delete_data_on_uninstall',!empty($_POST['delete_data'])?'yes':'no'); echo '<div class="updated"><p>Settings saved.</p></div>'; } ?>
 <div class="wrap"><h1>Customer Download Settings</h1><form method="post"><?php wp_nonce_field('cdp_save_settings'); ?><table class="form-table"><tr><th>Support email</th><td><input type="email" name="support_email" class="regular-text" value="<?php echo esc_attr(get_option('cdp_support_email','')); ?>"></td></tr><tr><th>Support phone</th><td><input name="support_phone" class="regular-text" value="<?php echo esc_attr(get_option('cdp_support_phone','')); ?>"></td></tr><tr><th>Support portal URL</th><td><input type="url" name="support_url" class="regular-text" value="<?php echo esc_attr(get_option('cdp_support_url','')); ?>"></td></tr><tr><th>Danger zone</th><td><label><input type="checkbox" name="delete_data" value="1" <?php checked(get_option('cdp_delete_data_on_uninstall','no'),'yes'); ?>> Remove all plugin database tables and protected files when plugin is deleted</label><p class="description">Default is safe: keep all data when plugin is deleted.</p></td></tr></table><p><button class="button button-primary" name="cdp_save_settings" value="1">Save Settings</button></p></form></div><?php }
